mapper.select:
SELECT av.id, av.name, av.venue_type, av.description, av.location, av.max_capacity, av.equipment, av.contact, av.require_approval, av.reserve_rule, av.images, av.remark, av.order_num, av.enabled, av.create_time, av.update_time FROM act_venue av WHERE av.enabled = '1'
AND av.name LIKE CONCAT('%', #{req.name}, '%')
AND av.venue_type = #{req.venueType}
AND av.enabled = #{req.enabled}
${req.dataScopeSql}
ORDER BY av.order_num ASC, av.id DESC
